import{_ as e,o as s,c as a,ai as t}from"./chunks/framework.Di2lRXru.js";const c=JSON.parse('{"title":"Linux - Running Payload Injector without root","description":"","frontmatter":{},"headers":[],"relativePath":"extras/adding_udev.md","filePath":"extras/adding_udev.md"}'),l={name:"extras/adding_udev.md"};function n(o,i,h,d,r,p){return s(),a("div",null,[...i[0]||(i[0]=[t('<h1 id="linux-running-payload-injector-without-root" tabindex="-1">Linux - Running Payload Injector without root <a class="header-anchor" href="#linux-running-payload-injector-without-root" aria-label="Permalink to “Linux - Running Payload Injector without root”">​</a></h1><p>This section details how to add an <code>udev</code> rule to let you send a payload to your Switch without needing to use <code>sudo</code>.</p><p>The following instructions only work if you have a system that implements <code>udev</code>. Most modern distros come with <code>systemd</code> already installed, which includes a <code>udev</code> implementation.</p><p>Do the following instructions while your Switch is <em>not</em> connected to your computer.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p><strong>For Arch Linux users:</strong></p><p>The package <code>android-udev</code> includes rules that will also allow for payload injection to work without root. Do note this also allows Android specific commands such as <code>adb</code> and <code>fastboot</code> to also work without root (as is the intention of it.)</p></div><h2 id="option-i-manually-adding-rules-and-group" tabindex="-1">Option I - Manually adding rules and group <a class="header-anchor" href="#option-i-manually-adding-rules-and-group" aria-label="Permalink to “Option I - Manually adding rules and group”">​</a></h2><p>The following instructions are not for beginners. Only do this if you understand what you are doing.</p><h3 id="creating-a-new-group" tabindex="-1">Creating a new group <a class="header-anchor" href="#creating-a-new-group" aria-label="Permalink to “Creating a new group”">​</a></h3><p>To start, we will create a new group and add ourselves to it. The group the Nintendo Switch device will be owned by on Linux will be set to this group.</p><ol><li><p>Open a terminal.</p></li><li><p>Enter the following command:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> groupadd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nintendo_switch</span></span></code></pre></div></li><li><p>Enter your password when prompted.</p></li><li><p>Enter the following command. Make sure that the <code>G</code> is capitalized:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> usermod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -G</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nintendo_switch</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $USER</span></span></code></pre></div></li><li><p>Close the terminal.</p></li></ol><h3 id="adding-a-udev-rule" tabindex="-1">Adding a udev rule <a class="header-anchor" href="#adding-a-udev-rule" aria-label="Permalink to “Adding a udev rule”">​</a></h3><p>Next, we will add a new <code>udev</code> rule. <code>udev</code> is a device manager for the linux kernel. The rule we will specify is that if the Switch is connected in <code>RCM</code>, the group the Switch belongs to will be the group we made in the previous section.</p><ol><li><p>Open a terminal.</p></li><li><p>Change to the root user with the following command.. Enter your password when prompted:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span></span></code></pre></div></li><li><p>Enter the following command:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/udev/rules.d</span></span></code></pre></div></li><li><p>Enter the following command:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;SUBSYSTEMS==&quot;usb&quot;, ATTRS{manufacturer}==&quot;NVIDIA Corp.&quot;, ATTRS{product}==&quot;APX&quot;, GROUP=&quot;nintendo_switch&quot;&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/udev/rules.d/10-switch.rules</span></span></code></pre></div></li><li><p>Enter the following command:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">udevadm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> control</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --reload</span></span></code></pre></div></li><li><p>Enter the following command:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">udevadm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trigger</span></span></code></pre></div></li><li><p>Logout and log back in.</p></li></ol><p>You should now be able to run the payload sender without having to use <code>sudo</code>.</p><h2 id="option-ii-installing-a-package-with-the-rules" tabindex="-1">Option II - Installing a package with the rules <a class="header-anchor" href="#option-ii-installing-a-package-with-the-rules" aria-label="Permalink to “Option II - Installing a package with the rules”">​</a></h2><p>These rules will actually allow <em>ANY</em> user to access your Switch via USB, not only <em>your</em> user.</p><p>You may just follow the instructions at <a href="https://github.com/pheki/nx-udev" target="_blank" rel="noreferrer">nx-udev</a>, or if you&#39;re on Ubuntu / Debian:</p><ol><li><p>Download <a href="https://github.com/pheki/nx-udev/releases/latest/download/nx-udev_latest_all.deb" target="_blank" rel="noreferrer">nx-udev_latest_all.deb</a>.</p></li><li><p>Open a terminal in the same directory as your download.</p></li><li><p>Run the following command to install the package:</p><div class="language-shell"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dpkg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nx-udev_latest_all.deb</span></span></code></pre></div></li></ol><p>You should now be able to run the payload injector and homebrew with USB communication without having to use <code>sudo</code>.</p>',19)])])}const g=e(l,[["render",n]]);export{c as __pageData,g as default};
